INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'C2AO-T', 'アースターミナルボックス (透明蓋 屋根無)', 'IV線: 5.5mm²×10。病院、診療所における感電防止対策に用いる、医療設備用接地センタ付です。吊りボルトに取り付け可能なボルトクリップ付。', 17400, 'https://dummyimage.com/200x200/cccccc/000.png&text=C2AO-T', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 195, 274, 130);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBC-1J', '防水コンセントボックス 防水コンセント付 (ベージュ色)', '蓋を開けずにプラグが差し込めます。防水コンセントですから雨にも安心!基台にはバンド通し穴が設けてあります。規格: 漏電しゃ断器(2P-1E20A・OC付)感度電流30mA、防水コンセント2ヶ用、接地極付・アースターミナル付 15A-125V。', 21000, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBC-1J', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 89, 270, 89);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBC-1NJ', '防水コンセントボックス 防水コンセント付 (ベージュ色)', '蓋を開けずにプラグが差し込めます。防水コンセントですから雨にも安心!基台にはバンド通し穴が設けてあります。規格: 防水コンセント2ヶ用、接地極付・アースターミナル付 15A-125V。', 12700, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBC-1NJ', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 89, 270, 89);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBKS-1M', 'プロテクトカバー (屋内用スリム L型プラグ用)', '冷蔵庫、エアコン等の常設のコンセントに最適です。スリムな設計なので、コンセントスペースが狭い箇所に最適です。(L型プラグ使用)L型プラグ用は埃が入りにくく、トラッキング火災防止に最適です。カバー付なので、スイッチを取り付けた場合の誤操作防止にもなります。色: ミルキーホワイト。適合プレート: 一連用。', 1160, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBKS-1M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 91, 140, 35);
