INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBKS-2M', 'プロテクトカバー (屋内用スリム L型プラグ用)', '冷蔵庫、エアコン等の常設のコンセントに最適です。スリムな設計なので、コンセントスペースが狭い箇所に最適です。(L型プラグ使用)L型プラグ用は埃が入りにくく、トラッキング火災防止に最適です。カバー付なので、スイッチを取り付けた場合の誤操作防止にもなります。色: ミルキーホワイト。適合プレート: 二連用。', 2080, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBKS-2M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 138, 140, 35);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBKS-RM', 'プロテクトカバー (屋内用スリム リモコン用)', '冷蔵庫、エアコン等の常設のコンセントに最適です。スリムな設計なので、コンセントスペースが狭い箇所に最適です。(L型プラグ使用)L型プラグ用は埃が入りにくく、トラッキング火災防止に最適です。カバー付なので、スイッチを取り付けた場合の誤操作防止にもなります。色: ミルキーホワイト。対応機種(サイズ): エアコン・給湯器(120×120)。', 2080, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBKS-RM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 138, 175, 32.3);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBK-1M', 'プロテクトカバー (器具用保護カバー)', 'コンセントやスイッチ等の器具を保護するタテ開きの開閉蓋付カバーです。厨房、トイレ等水回りのコンセント保護にも使用できます。器具を水やイタズラから守ります。一連用プレート用。(器具取付ピッチ83.5mm)。コンセントのプラグを差した状態で蓋を閉めることができます。給電ポールにも取り付けOK! ベロを折り取ると、プラグを差した状態で蓋を閉めることができます。(IPX3相当)。蓋のノックを開けると、南京錠が取り付けられます。(鍵付は除く)', 1640, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBK-1M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 91, 167, 71);
