INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MRD-DK2', '電力計取付板固定金具', 'ラクダシポールへの電力計ボックス・電力計取付板等の取り付けに使用します。ラクダシポールの上柱、下柱どちらでも取り付けられます。ラクダシポールへの仮固定ができます。', 460, 'https://dummyimage.com/200x200/cccccc/000.png&text=MRD-DK2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MRD-KSTK', 'ラクダシポール用 単管クランプ', '工事現場や災害復旧の仮設用途として、施設された単管に直接ラクダシポールを固定するクランプです。ラクダシポールにアンテナやカメラなどを取り付けて使用します。単管への固定により、仮設現場において穴を掘らずにラクダシポールを設置することができるため、撤去時も含め、現場の省力化が可能です。ラクダシポールへの機器取付用金具付。', 8780, 'https://dummyimage.com/200x200/cccccc/000.png&text=MRD-KSTK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 140, 215, 99);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MRDS-15', 'ラクスタンド', '柱本体は軽く、錆びにくいアルミ製の仮設電源用スタンドです。配線・配管をカバーで隠すことができます。三脚式なので、どこにでも簡単に設置できます。(アンカー打ちや、キャスターの取り付けも可能)。MRDS-30は脚部を畳めば全長3m以下に収まります。頑丈な設計なので、大型の仮設電源ボックスの取り付けにも耐えられます。脚部は錆びに強い溶融亜鉛スズ合金めっき。', 76600, 'https://dummyimage.com/200x200/cccccc/000.png&text=MRDS-15', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 1300, 3000, 1300);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MRDS-30', 'ラクスタンド', '柱本体は軽く、錆びにくいアルミ製の仮設電源用スタンドです。配線・配管をカバーで隠すことができます。三脚式なので、どこにでも簡単に設置できます。(アンカー打ちや、キャスターの取り付けも可能)。MRDS-30は脚部を畳めば全長3m以下に収まります。頑丈な設計なので、大型の仮設電源ボックスの取り付けにも耐えられます。脚部は錆びに強い溶融亜鉛スズ合金めっき。', 106700, 'https://dummyimage.com/200x200/cccccc/000.png&text=MRDS-30', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 1300, 3000, 1300);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KST-TS1', '仮設単管スタンド', '仮設現場でのウオルボックス等の取り付けに使用します。三脚式なので、どこにでも簡単に設置できます。コンパクトで運搬も非常にラクです。丈夫な単管を使用しています。用途に応じて開脚角度を変更して使用できます。', 16700, 'https://dummyimage.com/200x200/cccccc/000.png&text=KST-TS1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 1080, 1280, 1080);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), '5G-P', '5Gアンテナ用ポール', '5Gのアンテナを室内に設置する場合に使用するポールです。ポールをつっかえ棒のように設置して、下面をアンカー固定、天井面を下地材にビス固定で簡単に設置できます。レイアウト変更にも容易に対応できます。壁面の補強に比べ低コストで施工できます。設置可能天井高は3mです。(天井高に合わせてポールをカットします。ご注文時に天井高さをお伝えください。)', 66100, 'https://dummyimage.com/200x200/cccccc/000.png&text=5G-P', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 250, 2990, 250);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MCH-1', 'ケーブルハンガー (多機能タイプ)', '仮設現場の単管やワイヤーにボルトを利用し、仮設ケーブルを配線する場合に使用します。', 240, 'https://dummyimage.com/200x200/cccccc/000.png&text=MCH-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 66.6, 101, 16);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KSTH', 'ケーブルハンガー (仮設用)', '仮設現場での単管やワイヤー等を利用して、ケーブル等を取り付ける場合に使用します。単管やワイヤーに引っ掛けるだけの簡単取り付けです。ケーブルハンガーをねじで連結することにより、2連、3連吊りができます。直接、壁面への固定もできます。', 430, 'https://dummyimage.com/200x200/cccccc/000.png&text=KSTH', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KSTH-L', 'ケーブルハンガー (仮設用)', '仮設現場での単管やワイヤー等を利用して、ケーブル等を取り付ける場合に使用します。単管やワイヤーに引っ掛けるだけの簡単取り付けです。ケーブルハンガーをねじで連結することにより、2連、3連吊りができます。直接、壁面への固定もできます。', 500, 'https://dummyimage.com/200x200/cccccc/000.png&text=KSTH-L', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KSTHC', 'ケーブルハンガー (仮設用) (被覆付)', '仮設現場での単管やワイヤー等を利用して、ケーブル等を取り付ける場合に使用します。単管やワイヤーに引っ掛けるだけの簡単取り付けです。ケーブルハンガーをねじで連結することにより、2連、3連吊りができます。直接、壁面への固定もできます。被覆付は、ケーブル支持部に樹脂被覆が施してある為、ケーブルを傷めません。', 570, 'https://dummyimage.com/200x200/cccccc/000.png&text=KSTHC', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
