INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WPS-2J', '電力量計ボックス WPS-2型 ベージュ', 'スマートメーター用・隠ぺい型 e-デザイン 自己消火性樹脂製 屋外用 IP33D。フロント透明カバー付。施工がスッキリ。建物の美観を損なわない、オシャレでシャープなデザイン。雨水や虫の侵入を防ぐ防雨型。ポールにも取り付け可能。適合電力量計:1φ2W ~120A, 3φ3W 30A-60A。貫通材内径 Φ28, 適用電線 14mm²。', 8480, 'https://dummyimage.com/200x200/cccccc/000.png&text=WPS-2J', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 194, 460, 104);
