INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'RDIW-80RW', 'コーナーウォールカバー', '色:ルームホワイト, 壁貫通箇所がコーナー箇所にある場合に使用します。適合配管キャップ GHC-60~100, 適合その他のツバ付きスリーブ ツバ外径:φ136以下 ツバ高さ:10mm以下, ルームダクト', 1660, 'https://dummyimage.com/200x200/cccccc/000.png&text=RDIW-80RW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 140, 158, 76.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'RDIWL-80RW', 'コーナーウォールカバー (ロングタイプ)', '色:ルームホワイト, 壁貫通箇所がコーナー付近にある場合に使用します。ベースの先端部分を切り取ってから折り曲げることにより、壁貫通箇所からの距離を30mm単位で調整可能です。適合配管キャップ GHC-60~100, 適合その他のツバ付きスリーブ ツバ外径:φ136以下 ツバ高さ:10mm以下, ルームダクト', 2050, 'https://dummyimage.com/200x200/cccccc/000.png&text=RDIWL-80RW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 140, 270, 76.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBKS-1M', 'プロテクトカバー(屋内用スリム) L型プラグ用 一連用', '色:ミルキーホワイト, 冷蔵庫、エアコン等の常設のコンセントに最適です。スリムな設計なので、コンセントスペースが狭い箇所に最適です。(L型プラグ使用)L型プラグ用は埃が入りにくく、トラッキング火災防止に最適です。自己消火性で、スパークしても火花や火炎を外には出しません。カバー付なので、スイッチを取り付けた場合の誤操作防止にもなります。二連用・リモコン用は南京錠が取り付けられます。', 1160, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBKS-1M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 75, 100, 36.8);
