INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DPTS-16G', 'ドレンパイプ付属品 チーズ(ショートタイプ)', 'ドレンパイプ同士の接続等に使用します。従来品に比べ、短くなって見た目がスッキリ、耐候性もアップ。ドレン排水が流れやすい1.2° (2%)の勾配付です。接続口端部に45°ずつの印が付いているのでドレン配管の角度調整が簡単です。内径が平滑になるDV接続形状なので、ドレン水の流れがスムーズでゴミ等が溜まりにくくなっています。色:グレー, 呼び径:16, 適合管:VP-16・VE-16・DP-16', 190, 'https://dummyimage.com/200x200/cccccc/000.png&text=DPTS-16G', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 56, 28, 25.4);
