INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'VPS-13K', 'VP台付サドル', '住宅にマッチするカラーです。ドレンパイプを壁面より浮かせて固定できます。(市販のVP管にも使用できます。)カバーとベースの分割式ですから、ベースの先付けができます。スペーサーを重ね合わせてVP台付サドルの高さ調整ができます。色:黒, 適合管:ドレンパイプ DP-14/VP13', 180, 'https://dummyimage.com/200x200/cccccc/000.png&text=VPS-13K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, 25.5, 20);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'VPSS-13K', 'VP台付サドル用スペーサー', 'VP台付サドル用スペーサー色:黒, 適用:VPS-13K, 台高さ:5mm', 140, 'https://dummyimage.com/200x200/cccccc/000.png&text=VPSS-13K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, 5, 20);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DPES-14K', 'ドレンパイプ付属品 エルボ(ショートタイプ)', '住宅にマッチするカラーです。ドレンパイプ同士の接続等に使用します。従来品に比べ、短くなって見た目がスッキリ、耐候性もアップ。ドレン排水が流れやすい1.2° (2%)の勾配付です。接続口端部に45°ずつの印が付いているのでドレン配管の角度調整が簡単です。内径が平滑になるDV接続形状なので、ドレン水の流れがスムーズでゴミ等が溜まりにくくなっています。色:黒, 呼び径:14, 適合管:VP-13・VE-14・DP-14', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=DPES-14K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 26, 15, 21.4);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DPNS-14K', 'ドレンパイプ付属品 エルボ45°(ショートタイプ)', '住宅にマッチするカラーです。ドレンパイプ同士の接続等に使用します。従来品に比べ、短くなって見た目がスッキリ、耐候性もアップ。接続口端部に45°ずつの印が付いているのでドレン配管の角度調整が簡単です。内径が平滑になるDV接続形状なので、ドレン水の流れがスムーズでゴミ等が溜まりにくくなっています。色:黒, 呼び径:14, 適合管:VP-13・VE-14・DP-14', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=DPNS-14K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 21, 15, 21.4);
