INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DA-TR', 'ドレン配管トラップ (露出施工・マス内施工兼用)', 'エコジョーズ等のドレン配管を排水管や汚水マス等に接続する場合に使用するトラップです。(DA-TR (M)は露出施工、マス内施工両方に対応しています。)キャップの取り付け、取り外しが簡単でメンテナンスが容易です。エルボ×1個付(品番:DPE-14(G))※マス内施工時に使用します。色:グレー, 適合付属品:VP13用・VE14用・DP14用付属品, DA-KHS (M), 適合管:VP-13・VE-14・DP-14', 1160, 'https://dummyimage.com/200x200/cccccc/000.png&text=DA-TR', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 37, 61, 18);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DA-TRM', 'ドレン配管トラップ (露出施工・マス内施工兼用)', 'エコジョーズ等のドレン配管を排水管や汚水マス等に接続する場合に使用するトラップです。(DA-TR (M)は露出施工、マス内施工両方に対応しています。)キャップの取り付け、取り外しが簡単でメンテナンスが容易です。エルボ×1個付(品番:DPE-14(G))※マス内施工時に使用します。色:ミルキーホワイト, 適合付属品:VP13用・VE14用・DP14用付属品, DA-KHS (M), 適合管:VP-13・VE-14・DP-14', 1160, 'https://dummyimage.com/200x200/cccccc/000.png&text=DA-TRM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 37, 61, 18);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DA-TR2025', 'ドレン配管トラップ (20/25サイズ用)', 'エコジョーズ等のドレン配管を排水管や汚水マス等に接続する場合に使用するトラップです。(DA-TR (M)は露出施工、マス内施工両方に対応しています。)キャップの取り付け、取り外しが簡単でメンテナンスが容易です。色:グレー, 適合付属品:VP25用・DP25用付属品, 適合管:VP-20・VE-22・DP-20', 1390, 'https://dummyimage.com/200x200/cccccc/000.png&text=DA-TR2025', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 37, 91, 32.4);
