INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DA-TR2025D', 'ドレン配管トラップ (保温材付 20/25サイズ用)', 'エコジョーズ等のドレン配管を排水管や汚水マス等に接続する場合に使用するトラップです。(DA-TR (M)は露出施工、マス内施工両方に対応しています。)キャップの取り付け、取り外しが簡単でメンテナンスが容易です。保温材の下部が取り外し可能なのでメンテナンス時に便利です。色:グレー, 種類:保温材付, 適合付属品:VP25用・DP25用付属品, 適合管:VP-20・VE-22・DP-20', 2780, 'https://dummyimage.com/200x200/cccccc/000.png&text=DA-TR2025D', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 101.4, 145, 32.4);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DA-TR2025DM', 'ドレン配管トラップ (保温材付 20/25サイズ用)', 'エコジョーズ等のドレン配管を排水管や汚水マス等に接続する場合に使用するトラップです。(DA-TR (M)は露出施工、マス内施工両方に対応しています。)キャップの取り付け、取り外しが簡単でメンテナンスが容易です。保温材の下部が取り外し可能なのでメンテナンス時に便利です。色:ミルキーホワイト, 種類:保温材付, 適合付属品:VP25用・DP25用付属品, 適合管:VP-20・VE-22・DP-20', 2780, 'https://dummyimage.com/200x200/cccccc/000.png&text=DA-TR2025DM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 101.4, 145, 32.4);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BWMH-10A25', 'マルチドレンホース(通水確認型)', 'パッケージエアコンのドレン水をドレンアップさせる際に使用する断熱材付フレキ管です。ドレンポンプからの通水を配管側継手(ストレートプラグ)から目視可能です。袋ナットのゆるみ防止と接続完了の確認ができるクリップ付です。BWMH-10A25はストレートプラグ部が断熱空気層構造なので別売の保温材を使用すればテープ巻き等の保温工事が不要です。適合管:機器側: VP(20.25)・DP(20.25)・VE22 / 配管側:結露防止層付塩ビ管25用継手', 4470, 'https://dummyimage.com/200x200/cccccc/000.png&text=BWMH-10A25', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 75, 75, 1188);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BWMH-10V25', 'マルチドレンホース(通水確認型)', 'パッケージエアコンのドレン水をドレンアップさせる際に使用する断熱材付フレキ管です。ドレンポンプからの通水を配管側継手(ストレートプラグ)から目視可能です。袋ナットのゆるみ防止と接続完了の確認ができるクリップ付です。BWMH-10A25はストレートプラグ部が断熱空気層構造なので別売の保温材を使用すればテープ巻き等の保温工事が不要です。適合管:機器側: VP(20.25)・DP(20.25)・VE22 / 配管側:VP25用継手', 4470, 'https://dummyimage.com/200x200/cccccc/000.png&text=BWMH-10V25', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 75, 75, 1195);
