INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DKTP', '結露防止テープ', '色: 白, サイズ: 200×300mm, 厚み: 0.5mm, 結露防止、遮熱に優れたテープです。ボックス、配電盤、エアコンの貫通スリーブ等の結露防止処理に最適です。※任意の形状にカットして貼るだけです。特殊塗料にホルムアルデヒド等の揮発性化合物は含まれていません。', 1620, 'https://dummyimage.com/200x200/cccccc/000.png&text=DKTP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 200, 0.5);
