INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ADT-50', 'アルミダクトテープ (剥離紙付)', 'アルミ箔/厚み:0.05mm. 当社アルミフリーダクト接続部のテーピングに使用します。耐熱性・耐候性・耐寒性に優れたアルミ箔粘着テープです。使用温度:5~60℃. 剥離紙付は、必要な長さだけカットして使用する場合に便利です。', 4900, 'https://dummyimage.com/200x200/cccccc/000.png&text=ADT-50', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, NULL, NULL);
