INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYPB-100', '換気扇固定台座 (樹脂製 ミルキーホワイト色)', '適合パイプ: 換気パイプ100. 壁・天井への換気扇の取り付けに使用します。壁裏の補強材は不要です。野縁の無い天井裏にも取り付けられます。予め排水勾配(2°)が設けてあります。磁石付ですからEGアッター(磁石探知器)等で、ポイントの探知ができホルソーで穴あけができます。換気扇のケーブル隠ぺい用引き出し穴が設けてあります。付属の木ねじで間柱に固定できます。換気扇が自在な位置に取り付けられる、固定穴付基台です。', 730, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYPB-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 200, 200, 30);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYPB-150', '換気扇固定台座 (樹脂製 ミルキーホワイト色)', '適合パイプ: 換気パイプ150, アルミフリーダクト150. 壁・天井への換気扇の取り付けに使用します。壁裏の補強材は不要です。野縁の無い天井裏にも取り付けられます。予め排水勾配(2°)が設けてあります。磁石付ですからEGアッター(磁石探知器)等で、ポイントの探知ができホルソーで穴あけができます。換気扇のケーブル隠ぺい用引き出し穴が設けてあります。付属の木ねじで間柱に固定できます。換気扇が自在な位置に取り付けられる、固定穴付基台です。', 1070, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYPB-150', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 250, 250, 33);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYG-100', '換気扇固定台座用ドリルガイド', '適合: 換気扇固定台座 (PYPB-150は除く). 適合ドリル: φ6×200. 換気扇固定台座取り付け後の外壁開口用穴開けガイドとして使用します。', 100, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYG-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYPT-100', '換気扇固定台座 (天井用) (樹脂製 ミルキーホワイト色)', '適合: アルミフリーダクト100, 換気パイプ100. 天井・壁への換気扇の取り付けに使用します。アルミフリーダクト接続が簡単なアダプター付。野縁の無い天井裏にも簡単に取り付けられます。壁裏の補強材は不要です。磁石付ですからEGアッター(磁石探知器)等で、ポイントの探知ができ、ホルソーでの穴あけが容易です。適用: 換気扇100用. 機種により取り付けできない換気扇があります。奥行きをご確認ください。※奥行き最大42mmまで。', 840, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYPT-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 185, 185, 30);
