INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SVC-3DSL', 'ロクリップ (樹脂製吊りバンド付)', '適合ボルト: W3/8-M10. 吊りバンド: 幅15mm, 長さ900mm. 適合ダクト径: φ50~φ150. 吊りボルトへのダクト、換気パイプ等の取り付け(支持)に使用します。吊りボルトヘワンタッチで取り付けられます。吊りバンド(樹脂製)に簡単に取り付けられるバンド無タイプもあります。水平、垂直、斜め45°の角度調整可能。許容静荷重:20N(2kgf). 推奨取付ピッチ: 1.5m以下. 使用温度:60℃迄。', 360, 'https://dummyimage.com/200x200/cccccc/000.png&text=SVC-3DSL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SVC-3DL', 'ロクリップ (樹脂製吊りバンド付)', '適合ボルト: W1/2-M12. 吊りバンド: 幅25mm, 長さ908mm. 適合ダクト径: φ50~φ150. 吊りボルトへのダクト、換気パイプ等の取り付け(支持)に使用します。吊りボルトヘワンタッチで取り付けられます。吊りバンド(樹脂製)に簡単に取り付けられるバンド無タイプもあります。水平、垂直、斜め45°の角度調整可能。許容静荷重:20N(2kgf). 推奨取付ピッチ: 1.5m以下. 使用温度:60℃迄。', 390, 'https://dummyimage.com/200x200/cccccc/000.png&text=SVC-3DL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SVC-3D', 'ロクリップ (バンド無)', '適合ボルト: W3/8-M10, W1/2-M12. 適合吊りバンド: MDBP-15, MDBP-25. 吊りボルトへのダクト、換気パイプ等の取り付け(支持)に使用します。吊りボルトヘワンタッチで取り付けられます。吊りバンド(樹脂製)に簡単に取り付けられるバンド無タイプもあります。水平、垂直、斜め45°の角度調整可能。許容静荷重:20N(2kgf). 推奨取付ピッチ: 1.5m以下. 使用温度:60℃迄。', 66, 'https://dummyimage.com/200x200/cccccc/000.png&text=SVC-3D', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SVC-3DB', 'ロクリップ (ワンタッチハンガー)', '適合ボルト: W3/8-M10, W1/2-M12. 適合吊りバンド: MDBP-15, MDBP-25. 吊りバンドをフックに引っ掛けるだけの簡単施工。吊りボルトヘワンタッチで取り付けられます。許容静荷重:9.8N(1kgf). 推奨取付ピッチ:1.5m以下. 使用温度:60℃迄。', 73, 'https://dummyimage.com/200x200/cccccc/000.png&text=SVC-3DB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MDBP-8', '吊りバンド (結束バンドタイプ 樹脂製)', '幅: 8mm, 長さ: 50m, 厚み: 1.5mm. 許容静荷重: 20N (2kgf). アルミフリーダクトや換気パイプ等の吊り下げ支持に使用します。任意の位置(長さ)で切断して使用できます。固定具に差し込むだけで、簡単確実に取り付けられます。使用温度:60℃迄。', 5770, 'https://dummyimage.com/200x200/cccccc/000.png&text=MDBP-8', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 8, NULL, NULL);
