INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MDBP-8S', 'バンドフックサドル (吊りバンド(結束バンドタイプ)用)', '適合吊りバンド: MDBP-8. 適合ダクト径: φ30以上. 吊りバンドによる木柱等へのダクト、換気パイプ等の取り付け(支持)に使用します。差し込むだけで、簡単確実に取り付けられます。解除も簡単にできます。許容静荷重:20N(2kgf). 使用温度:60℃迄。', 89, 'https://dummyimage.com/200x200/cccccc/000.png&text=MDBP-8S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 35, 37.5, NULL);
