INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGMH', '形鋼金具用サポート金具 (SGM・SGMK用) H形鋼用 ボルト無', '形鋼金具(SGM-SGMK)。鋼材に取り付けた形鋼金具を振動に対して、外れにくくするための補強金具です。取り付け後も形鋼金具に吊りボルトを通すことができます。※吊りボルトへの器具等の取り付けは、サポート金具を取り付けてから行ってください。※取り付けには、市販のW3/8寸切りボルト(長さ=H形鋼幅+20mm)が別途必要です。', 620, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGMH', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 79, 44, 42);
