INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGK', '形鋼金具 H・L形鋼用', 'H・L形鋼(鋼材厚3~16mm)。クリップと組み合わせ、鋼材に電線管等を取り付ける場合に使用します。結束バンド等を使用し、ケーブル等の固定もできます。(バンド幅10mm迄) クリップは2箇所に取り付けできます。クリップの向きは、4方向(45°)に設定できます。形鋼金具を外さず取り付けできます。高天井用照明器具・電線管等の取り付けに最適です。', 120, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 42, 41, 31);
