INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGMY', '形鋼金具 (アイボルト付、RoHS対応)', '振れ止めワイヤーの取り付けに使用。適合寸法(A): H形鋼(鋼材厚7～30mm)。垂直許容静荷重: 980N(100kgf)。斜め許容静荷重: 490N(50kgf)。取り付けには、市販のW3/8寸切りボルト(長さ=H形鋼幅+20mm)が別途必要。アイボルトに振れ止めワイヤーを取り付ける場合はワイヤーが垂直に対し45°以内になるように取り付けること。', 1640, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGMY', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 55, 44);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGMKY', '形鋼金具 (アイボルト付、高強度タイプ、RoHS対応)', '振れ止めワイヤーの取り付けに使用。適合寸法(A): H形鋼(鋼材厚7～30mm)。垂直許容静荷重: 2156N(220kgf)。斜め許容静荷重: 1176N(120kgf)。取り付けには、市販のW3/8寸切りボルト(長さ=H形鋼幅+20mm)が別途必要。アイボルトに振れ止めワイヤーを取り付ける場合はワイヤーが垂直に対し45°以内になるように取り付けること。', 2440, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGMKY', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 55, 44);
