INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLBP-150', 'ブランクプレート (カベ白)', '色: カベ白。適用: 天井用。適合穴径: Φ50～Φ150。適合天井厚: 25mm迄。ダウンライト等を取り外した際の天井の不要な穴を塞ぐためのプレート。ばねを天井に引っ掛けるだけの簡単取り付け。', 940, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLBP-150', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 170, 45, 170);
