INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVM-OYTJ', '露出用丸型ボックス(ブランクタイプ) 1~4方出兼用型', '感知器、コンセントの取付用の木ねじ溝付です。添付の異径アダプターにより、2号コネクタが接続できます。ボックスと蓋の境目が無いスマートなデザインです。封印ビスが取り付けられます。高耐候性、耐衝撃性HI。2号コネクタ用異径アダプター2個、CDジョイントナット2個付。色:ベージュ。適合コネクタサイズ: G1 (28)、16・22(異径アダプター使用)。', 940, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVM-OYTJ', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 106, 100, 106);
