INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DLT-200', 'カメラ取付カバー(天井用)', '防犯カメラを更新する際、既存の取り付け穴を利用する場合に使用。ブランクカバーとしても使用可能。取付穴径: Φ125~Φ180。適合天井厚: 9.5~25迄。', 1840, 'https://dummyimage.com/200x200/cccccc/000.png&text=DLT-200', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 210, 31, 210);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'APD-60W', 'アクセスポイント用天井取付台座', '天井面にアクセスポイントや防犯カメラを取り付ける場合に使用します。2枚の大きなツメにより、シッカリ台座をはさみ固定します。台座中央の穴にケーブルブッシング(ZGV-P22M)をはめ込めば、ブランクプレートとしても使用できます。色:カベ白。取付天井厚: 0.5~25mm。取付穴径: Φ60~Φ62。', 1780, 'https://dummyimage.com/200x200/cccccc/000.png&text=APD-60W', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 120, 37.5, 120);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PV4B-KSTK', '単管サポート(防犯カメラ取付ボックス用)', '単管等に、防犯カメラ取付用ボックスを取付ける場合に使用。VESA規格に対応したモニターの取り付けも可能。単管横、単管縦のどちらにでも取付け可能。適合パイプ: Φ42.7~Φ48.6。', 3830, 'https://dummyimage.com/200x200/cccccc/000.png&text=PV4B-KSTK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 146.9, 159.9, 100);
