INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'M-10FAF', 'ミラックハンガー (薄型)(FRP製)', 'FRP製。高さ18.6mm。塩害に強く、加工も容易なFRP製。薄型なので仕上がりスッキリ! VE管、鋼管、PF管等の固定など多用途に使用できる短尺支持部材です。豊富な付属品と組み合わせることにより、様々な箇所に様々な部材を取り付けることができます。短尺物のほか、好きな長さにカットして使える2m物があります。上面が平らなので管を固定しても変形しにくくなっています。色:白。許容静荷重:196N (20kgf)。', 1160, 'https://dummyimage.com/200x200/cccccc/000.png&text=M-10FAF', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 43.8, 18.6, 100);
